parameters.query:
mutation CreateCard($input: CreateCardInput!) {
  createCard(input: $input) {
    card { id title }
  }
}

query Get1($cardId: ID!) {
  card(id: $cardId) {
    id
    title
    fields {
      field { id label type }
      value
      array_value
    }
  }
}

parameters.jsCode:
function asString(v) {
  if (v === null || v === undefined) return '';
  return String(v);
}

function uniq(arr) {
  return [...new Set(arr.filter(Boolean))];
}

function extractRegrasIds(card) {
  const fields = card?.fields || [];
  const f = fields.find(x => x?.field?.id === 'regras_de_faturamento');
  if (!f) return [];

  const av = f.array_value;
  if (Array.isArray(av)) {
    const out = av.map(v => {
      if (v === null || v === undefined) return '';
      if (typeof v === 'object') {
        if (v.id) return String(v.id);
        if (v.value) return String(v.value);
        return JSON.stringify(v);
      }
      return String(v);
    });
    return uniq(out);
  }

  const val = f.value;
  if (val === null || val === undefined) return [];
  if (typeof val === 'string') {
    const ids = val.match(/\d+/g);
    return uniq(ids && ids.length ? ids : [val]);
  }
  if (typeof val === 'object') return [JSON.stringify(val)];
  return [String(val)];
}

function containsId(list, id) {
  const needle = String(id);
  return (list || []).some(v => String(v).includes(needle));
}

function isEmpty(list) {
  return !list || list.length === 0;
}

function nodeJson(name) {
  // Access other node output robustly
  return $node?.[name]?.json;
}

function pushLog(id_do_teste, ok, observacoes) {
  const sd = $getWorkflowStaticData('global');
  if (!Array.isArray(sd.logs)) sd.logs = [];
  sd.logs.push({
    id_do_teste: String(id_do_teste),
    resultado: ok ? 'OK' : 'ERRO',
    observacoes: String(observacoes || '')
  });
}


const validation = nodeJson('T01 - Validar (card 1259910277)');
const createdId = $node["T01 - Criar card (Afiliados)"].json?.data?.createCard?.card?.id;

let ok = Boolean(createdId);

const card = validation?.data?.card;
const regras = extractRegrasIds(card);
if (!containsId(regras, createdId)) ok = false;

const obs = [
  `createCard.id=${asString(createdId)}`,
  `Esperado: 1259910277 conter ${createdId} em regras_de_faturamento`,
  `1259910277 -> ${JSON.stringify(regras)}`
].join(' | ');

pushLog('1', ok, obs);
return $input.all();

