function asString(v) {
  if (v === null || v === undefined) return '';
  return String(v);
}

function uniq(arr) {
  return [...new Set(arr.filter(Boolean))];
}

function extractRegrasIds(card) {
  const fields = card?.fields || [];
  const f = fields.find(x => x?.field?.id === 'regras_de_faturamento');
  if (!f) return [];

  const av = f.array_value;
  if (Array.isArray(av)) {
    const out = av.map(v => {
      if (v === null || v === undefined) return '';
      if (typeof v === 'object') {
        if (v.id) return String(v.id);
        if (v.value) return String(v.value);
        return JSON.stringify(v);
      }
      return String(v);
    });
    return uniq(out);
  }

  const val = f.value;
  if (val === null || val === undefined) return [];
  if (typeof val === 'string') {
    const ids = val.match(/\d+/g);
    return uniq(ids && ids.length ? ids : [val]);
  }
  if (typeof val === 'object') return [JSON.stringify(val)];
  return [String(val)];
}

function containsId(list, id) {
  const needle = String(id);
  return (list || []).some(v => String(v).includes(needle));
}

function isEmpty(list) {
  return !list || list.length === 0;
